import './App.css';
import { useState } from "react";

function App() {
  const [tasks, setTasks] = useState([
  { id: 1, title: "Study math", completed: false },
  { id: 2, title: "Work on project", completed: false }
]);
  return (
      <div>
        <h1>Focus Coach</h1>
        <ul>
  {tasks.map(task => (
    <li key={task.id}>{task.title}</li>
  ))}
</ul>
      </div>
  );
}

export default App;
